export interface HttpFetchOptions {
    /**
     * 超时时间
     */
    timeout?: number;
    /**
     * 是否通过 `http egress mesh` 发送请求，默认 `true`
     */
    enableMesh?: boolean;
    /**
     * 是否通过 `http egress mesh` 发送请求，默认 `false`，与 `enableMesh` 不同的是，该参数只适用于 `http://` 协议，如果需要 `http://` 协议走 `mesh` 可以开启该选项
     */
    enableHttpMesh?: boolean;
    /** @deprecated use options.enableMesh instead */
    disableMesh?: boolean;
}
